eft-menu': true, 'active': list.goTo === _vm.$route.path },staticStyle:{\"align-items\":\"center\"},attrs:{\"to\":list.goTo}},[_c('em',{staticClass:\"mr-2\",class:list.icon}),_vm._v(_vm._s(_vm.$t(_vm.TruncateStr(list.title, 25)))+\" \")])],1)}),0)])])],1)}\nvar staticRenderFns = [function () {var _vm=this;var _h=_vm.$createElement;var _c=_vm._self._c||_h;return _c('div',{staticClass:\"input-group-append\"},[_c('span',{staticClass:\"input-group-text bg-transparent bg-white border-left-0\"},[_c('em',{staticClass:\"fa fa-search\"})])])}]\n\nexport { render, staticRenderFns }","<template>\r\n    <div class=\"left-menu-tab mt-2\">\r\n        <loader :is-visible=\"isLoading\"></loader>\r\n        <div class=\"theme-primary partition\">\r\n            <span class=\"p-name text-white\">{{ $t('CompanySetup') }}</span>\r\n        </div>\r\n        <div class=\"left-tab-container\">\r\n            <div class=\"mb-0 d-lg-block p-2 border\">\r\n                <div class=\"input-group customsearchbox\">\r\n\r\n                    <input type=\"text\" maxlength=\"50\" v-on:keyup=\"ListFiltering\" id=\"searchinput\"\r\n                        v-model=\"moduleSearchElement\" placeholder=\"Search by Name\"\r\n                        class=\"form-control searchcustomfilter border-right-0\" autocomplete=\"off\">\r\n                    <div class=\"input-group-append\">\r\n                        <span class=\"input-group-text bg-transparent bg-white border-left-0\">\r\n                            <em class=\"fa fa-search\"></em>\r\n                        </span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div class=\"mt-2 mCustomScrollbar _mCS_4\">\r\n                <a class=\"card mobile-tab-accordian active\" href=\"javascript:;\" data-controllername=\"billingrule\"\r\n                    data-actionname=\"ImportFormatListing\" v-on:click=\"showMobileTabs = !showMobileTabs;\">\r\n                    <div class=\"card-header\" role=\"tab\">\r\n                        <h5><span class=\"mb-0\"><i :class=\"GetSelectedModuleItem.icon\"></i> {{\r\n                            $t(GetSelectedModuleItem.title) }}<i class=\"fa fa-angle-down rotate-icon float-right\"\r\n                                    aria-hidden=\"true\"></i></span>\r\n                        </h5>\r\n                    </div>\r\n                </a>\r\n                <div v-if=\"showMobileTabs\">\r\n                    <a class=\"card mobile-tab-accordian\" href=\"javascript:;\" v-for=\"list in leftTabList\"\r\n                        v-if=\"GetSelectedModuleItem.title != list.title\" :title=\"$t(list.title)\">\"\r\n                        v-on:click=\"SetCurrentTab(list.title); showMobileTabs = false;\">\r\n                        <div role=\"tab\" class=\"card-header\">\r\n                            <h5><span class=\"mb-0\">\r\n                                    <em :class=\"list.icon\"></em>{{ TruncateStr(list.title, 25) }}<em aria-hidden=\"true\"\r\n                                        class=\"fa fa-angle-down rotate-icon float-right\"></em>\r\n                                </span>\r\n                            </h5>\r\n                        </div>\r\n                    </a>\r\n                </div>\r\n                <ul class=\"nav nav-pills flex-column left-tab responivecustomtab lefttabiconfix\">\r\n                    <li v-for=\"list in leftTabList\" v-show=\"list.isVisible\" :title=\"$t(list.title)\" :key=\"KEY\">\r\n\r\n                        <router-link :to=\"list.goTo\" style=\"align-items: center;\"\r\n                            :class=\"{ 'nav-link left-menu': true, 'active': list.goTo === $route.path }\">\r\n                            <em :class=\"list.icon\" class=\"mr-2\"></em>{{ $t(TruncateStr(list.title, 25)) }}\r\n                        </router-link>\r\n                    </li>\r\n                </ul>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n</template>\r\n<style scoped>\r\n.left-tab-container {\r\n    max-height: 70vh;\r\n    /* Set the maximum height to the viewport height */\r\n    overflow-y: auto;\r\n    /* Enable vertical scrollbar when content exceeds the height */\r\n}\r\n\r\n.left-tab .nav-link.left-menu a {\r\n    width: 100%;\r\n    display: flex;\r\n}\r\n\r\n.left-tab .nav-link.left-menu:hover,\r\n.listing:hover {\r\n    color: #fff;\r\n}\r\n\r\n.left-tab .nav-link.left-menu.active .listing {\r\n    color: #fff;\r\n}\r\n</style>\r\n<script>\r\nimport dataService from \"@/services/DataService\";\r\nexport default {\r\n    name: \"listing-status\",\r\n    props: {\r\n        HeaderText: {\r\n            type: String,\r\n            required: true,\r\n        },\r\n    },\r\n    data: function () {\r\n        return {\r\n            CompanyId: null,\r\n            userId: null,\r\n            isLoading: false,\r\n            MainSearchmodel: '',\r\n            GetSelectedValue: '',\r\n            Header: this.HeaderText,\r\n            searchColumnfilter: [],\r\n            KEY:0,\r\n            moduleSearchElement: '',\r\n            currentTab: \"AnnouncementMessage\",\r\n            Header: this.HeaderText,\r\n            showMobileTabs: true,\r\n            defaultTabs: ['AnnouncementMessage', 'Department', 'Designation', 'EmailTemplate', 'CompanyHoliday', 'CurrencyManagement', 'UserTitle', 'CompanyNotification', 'Greeting', 'LoginAuthorization', 'Shift', 'Status'],\r\n            leftTabList: [\r\n                {\r\n                    title: 'AnnouncementMessage',\r\n                    icon: 'fa fa-bullhorn',\r\n                    goTo: '/AnnouncementMessage/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Break',\r\n                    icon: 'fa fa-clock-o',\r\n                    goTo: '/Break/Index',\r\n                    isShow: false\r\n                },\r\n                // {\r\n                //     title: 'Canned Reply',\r\n                //     icon: 'fa fa-envelope',\r\n                //     goTo: '/CannedReply/Index',\r\n                // },\r\n                {\r\n                    title: 'Category',\r\n                    icon: 'fa fa-tasks',\r\n                    goTo: '/Category/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Channel',\r\n                    icon: 'fa fa-television',\r\n                    goTo: '/Channel/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'CompanyHoliday',\r\n                    icon: 'fa fa-calendar',\r\n                    goTo: '/CompanyHoliday/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'CompanyNotification',\r\n                    icon: 'fa fa-bell',\r\n                    goTo: '/CompanyNotification/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'ContactType',\r\n                    icon: 'fa fa-list-alt',\r\n                    goTo: '/ContactType/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'CurrencyManagement',\r\n                    icon: 'fa fa-money',\r\n                    goTo: '/CurrencyManagement/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Department',\r\n                    icon: 'fa fa-users',\r\n                    goTo: '/Department/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Designation',\r\n                    icon: 'fa fa-address-card',\r\n                    goTo: '/Designation/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Discounts',\r\n                    icon: 'fa fa-usd',\r\n                    goTo: '/ClientBill/CreateDeductions',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'EmailTemplate',\r\n                    icon: 'fa fa-file-text-o',\r\n                    goTo: '/EmailTemplate/Index',\r\n                    isShow: false\r\n                },\r\n                // {\r\n                //     title: 'SMS Template',\r\n                //     icon: 'fa fa-comments',\r\n                //     goTo: '/SMSTemplate/Index',\r\n                // },\r\n                {\r\n                    title: 'Feedback',\r\n                    icon: 'fa fa-quote-left',\r\n                    goTo: '/Feedback/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Greeting',\r\n                    icon: 'fa fa-thumbs-o-up',\r\n                    goTo: '/Greeting/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'IndustryType',\r\n                    icon: 'fa fa-building-o',\r\n                    goTo: '/IndustryType/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Immigration',\r\n                    icon: 'fa fa-address-card',\r\n                    goTo: '/Immigration/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Location',\r\n                    icon: 'fa fa-map-marker',\r\n                    goTo: '/Location/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'LoginAuthorization',\r\n                    icon: 'fa fa-lock',\r\n                    goTo: '/LoginAuthorization/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Priority',\r\n                    icon: 'fa fa-check-square-o',\r\n                    goTo: '/Priority/Index',\r\n                    isShow: false\r\n                },\r\n                // {\r\n                //     title: 'Question',\r\n                //     icon: 'fa fa-question',\r\n                //     goTo: '/Question/Index?reqhFrom=0',\r\n                //     isShow: false\r\n                // },\r\n                {\r\n                    title: 'PasswordPolicy',\r\n                    icon: 'fa fa-cog',\r\n                    goTo: '/Company/add',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'PaymentGateway',\r\n                    icon: 'fa fa-credit-card',\r\n                    goTo: '/PaymentGateway/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'ProvisionalRight',\r\n                    icon: 'fa fa-check',\r\n                    goTo: '/ProvisionalRight/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'ReviewTemplate',\r\n                    icon: 'fa fa-file-text-o',\r\n                    goTo: '/ReviewTemplate/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Service',\r\n                    icon: 'fa fa-newspaper-o',\r\n                    goTo: '/Service/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Shift',\r\n                    icon: 'fa fa-clock-o',\r\n                    goTo: '/Shift/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Skill',\r\n                    icon: 'fa fa-star',\r\n                    goTo: '/Skill/Index',\r\n                    isShow: false\r\n                },\r\n                // {\r\n                //     title: 'Stage',\r