rentTab.toLowerCase()\r\n            });\r\n            return getModuleObj[0];\r\n        }\r\n    },\r\n    methods: {\r\n        SetCurrentTab: function (moduleName) {\r\n            this.currentTab = moduleName.toLowerCase();\r\n\r\n        },\r\n        getCompanySetupModulePrivilege: async function (url) {\r\n            //debugger;\r\n            let ths = this;\r\n            ths.isLoading = true;\r\n\r\n            try {\r\n\r\n                const response = await dataService.getCompanySetupModulePrivilege(url);\r\n\r\n\r\n                if (response != null && response.data != null && response.data.length > 0) {\r\n                    ths.isLoading = false;\r\n                    var data = response.data;\r\n\r\n\r\n                    ths.leftTabList.forEach(function (itm) {\r\n                        if (itm.title.toLowerCase().includes(ths.moduleSearchElement.toLowerCase())) {\r\n                            itm.isVisible = true;\r\n                        } else {\r\n                            itm.isVisible = false;\r\n                        }\r\n\r\n                        // Optionally, you can add logic to show/hide tabs based on certain conditions\r\n                        // let controllerName = itm.goTo.split(\"/\")[1];\r\n                        // var ifExists = data.find((x) => { return x.CONTROLER_NAME == controllerName});\r\n                        // if(ifExists || ths.defaultTabs.includes(controllerName) == true){\r\n                        //     itm.isShow = true;\r\n                        // }\r\n                    });\r\n                }\r\n            } catch (error) {\r\n\r\n                console.error(\"Error fetching company setup module privilege:\", error);\r\n                ths.isLoading = false;\r\n\r\n\r\n                ths.showErrorMessage(\"An error occurred while fetching company setup module privilege. Please try again later.\");\r\n            }\r\n        },\r\n\r\n        // getCompanySetupModulePrivilege: f