ck=\"checkAllRowCheckboxes($event,'chk_3','mobile')\">\r\n                                                    <label class=\"custom-control-label\" for=\"chkupper_3\"></label>\r\n                                                </div>\r\n                                                <span style=\"min-width:102px\" class=\"font-weight-normal float-left m-1\">\r\n                                                {{ $t('Mobile') }}\r\n                                                </span>\r\n                                            </th>\r\n                                            <th class=\"text-center\" style=\"width:102px\" scope=\"col\">\r\n                                                <div class=\"custom-control custom-checkbox\">\r\n                                                    <input type=\"checkbox\" id=\"chkupper_4\" data-change-id=\"no\"\r\n                                                        class=\"deletable custom-control-input\" v-on:click=\"checkAllRowCheckboxes($event,'chk_4','push')\">\r\n                                                    <label class=\"custom-control-label\" for=\"chkupper_4\"></label>\r\n                                                </div>\r\n                                                <span style=\"min-width:102px\" class=\"font-weight-normal float-left m-1\">\r\n                                                {{ $t('Push') }}\r\n                                                </span>\r\n                                            </th>\r\n                                        </tr>\r\n                                    </thead>\r\n                                    <tbody v-for=\"(parentitem, parentIndex) in GetNotificationData\" :key=\"parentIndex\" id=\"accordionEx\">\r\n                                        <tr class=\"high-bar\" :id=\"'MainColumn' + parentIndex\">\r\n                                            <td><span class=\"table-plus-minus\">\r\n                                                    <a class=\"collapsed\" data-parent=\"#accordionEx\"\r\n                                                        :data-target=\"'#ColumnCollapse' + parentIndex\"\r\n                                                        href=\"javascript:;\" aria-expanded=\"false\"\r\n                                                        :aria-controls=\"'ColumnCollapse' + parentIndex\"\r\n                                                        data-toggle=\"collapse\" @click=\"toggleAccordion(parentIndex)\" ><em :class=\"activeIndex === parentIndex ? 'fa fa-minus pt-0' : 'fa fa-plus pt-0'\"\r\n                                                            aria-hidden=\"true\"></em></a></span></td>\r\n                                            <td>\r\n                                                {{ parentitem.ModuleName }}\r\n                                            </td>\r\n                                            <td class=\"text-center \">\r\n                                                <div class=\"custom-control custom-checkbox\">\r\n                                                    <input type=\"checkbox\" :value=\"parentitem.ModuleId\"\r\n                                                        :id=\"'chk_1' + parentitem.ModuleId\" data-change-id=\"no\"\r\n                                                        v-on:click=\"checkAllCheckboxes($event,'chk_1' + parentitem.ModuleId,'email',parentIndex)\"\r\n                                                        class=\"deletable custom-control-input\" name=\"email\"\r\n                                                        :checked=\"parentitem.IS_EMAIL_NOTIFICATION == 1 ? 'checked' : ''\">\r\n                                                    <label class=\"custom-control-label\"\r\n                                                        :for=\"'chk_1' + parentitem.ModuleId\"></label>\r\n                                                </div>\r\n                                            </td>\r\n                                            <td class=\"text-center\">\r\n                                                <div class=\"custom-control custom-checkbox\">\r\n                                                    <input type=\"checkbox\" :value=\"parentitem.ModuleId\"\r\n                                                        v-on:click=\"checkAllCheckboxes($event,'chk_2' + parentitem.ModuleId,'inbox',parentIndex)\"\r\n                                                        :id=\"'chk_2' + parentitem.ModuleId\" data-change-id=\"no\"\r\n                                                        class=\"deletable custom-control-input\" name=\"inbox\"\r\n                                                        :checked=\"parentitem.IS_INBOX_NOTIFICATION == 1 ? 'checked' : ''\">\r\n                                                    <label class=\"custom-control-label\"\r\n                                                        :for=\"'chk_2' + parentitem.ModuleId\"></label>\r\n                                                </div>\r\n                                            </td>\r\n                                            <td class=\"text-center\">\r\n                                                <div class=\"custom-control custom-checkbox\">\r\n                                                    <input type=\"checkbox\" :value=\"parentitem.ModuleId\"\r\n                                                        v-on:click=\"checkAllCheckboxes($event,'chk_3' + parentitem.ModuleId,'mobile',parentIndex)\"\r\n                                                        :id=\"'chk_3' + parentitem.ModuleId\" data-change-id=\"no\"\r\n                                                        class=\"deletable custom-control-input\" name=\"mobile\"\r\n                                                        :checked=\"parentitem.IS_MOBILE_NOTIFICATION == 1 ? 'checked' : ''\">\r\n                                                    <label class=\"custom-control-label\"\r\n                                                        :for=\"'chk_3' + parentitem.ModuleId\"></label>\r\n                                                </div>\r\n                                            </td>\r\n                                            <td class=\"text-center\">\r\n                                                <div class=\"custom-control custom-checkbox\">\r\n                                                    <input type=\"checkbox\" :value=\"parentitem.ModuleId\"\r\n                                                        v-on:click=\"checkAllCheckboxes($event,'chk_4' + parentitem.ModuleId,'push',parentIndex)\"\r\n                                                        :id=\"'chk_4' + parentitem.ModuleId\" data-change-id=\"no\"\r\n                                                        class=\"deletable custom-control-input\" name=\"push\"\r\n                                                        :checked=\"parentitem.IS_PUSH_NOTIFICATION == 1 ? 'checked' : ''\">\r\n                                                    <label class=\"custom-control-label\"\r\n                                                        :for=\"'chk_4' + parentitem.ModuleId\"></label>\r\n                                                </div>\r\n                                            </td>\r\n                                        </tr>\r\n                                        <tr class=\"rowdata collapse collapseAppointment gray\"\r\n                                            v-for=\"inneritem in parentitem.GroupedSubmodule\"\r\n                                            :id=\"'ColumnCollapse' + parentIndex\" \r\n                                            v-if=\"parentitem.GroupedSubmodule.length > 0\"\r\n                                            :aria-labelledby=\"'MainColumn' + parentIndex\" data-parent=\"#accordionEx\">\r\n                                            <td></td>\r\n                                            <td>\r\n                                                {{ inneritem.TYPE_NAME }}\r\n                                            </td>\r\n                                            <td class=\"text-center\">\r\n                                                <div class=\"custom-control custom-checkbox\">\r\n                                                    <input type=\"checkbox\" :value=\"inneritem.ID\"\r\n                                                        v-on:click=\"checkAllOuterMainCheckboxes($event,parentIndex)\"\r\n                                                        :id=\"'chkinner_1' + inneritem.ID\" data-change-id=\"no\"\r\n                                                        class=\"deletable custom-control-input\" name=\"email\"\r\n                                                        :checked=\"inneritem.IS_EMAIL_NOTIFICATION == 1 ? 'checked' : ''\">\r\n                                                    <label class=\"custom-control-label\"\r\n                                                        :for=\"'chkinner_1' + inneritem.ID\"></label>\r\n                                                </div>\r\n                                            </td>\r\n                                            <td class=\"text-center\">\r\n                                                <div class=\"custom-control custom-checkbox\">\r\n                                                    <input type=\"checkbox\" :value=\"inneritem.ID\"\r\n                                                        v-on:click=\"checkAllOuterMainCheckboxes($event,parentIndex)\"\r\n                                                        :id=\"'chkinner_2' + inneritem.ID\" data-change-id=\"no\"\r\n                                                        class=\"deletable custom-control-input\" name=\"inbox\"\r\n                                                        :checked=\"inneritem.IS_INBOX_NOTIFICATION == 1 ? 'checked' : ''\">\r\n                                                    <label class=\"custom-control-label\"\r\n                                                        :for=\"'chkinner_2' + inneritem.ID\"></label>\r\n                                                </div>\r\n                                            </td>\r\n                                            <td class=\"text-center\">\r\n                                                <div class=\"custom-control custom-checkbox\">\r\n                                                    <input type=\"checkbox\" :value=\"inneritem.ID\"\r\n                                                        v-on:click=\"checkAllOuterMainCheckboxes($event,parentIndex)\"\r\n                                                        :id=\"'chkinner_3' + inneritem.ID\" data-change-id=\"no\"\r\n                                                        class=\"deletable custom-control-input\" name=\"mobile\"\r\n                                                        :checked=\"inneritem.IS_MOBILE_NOTIFICATION == 1 ? 'checked' : ''\">\r\n                                                    <label class=\"custom-control-label\"\r\n                                                        :for=\"'chkinner_3' + inneritem.ID\"></label>\r\n                                                </div>\r\n                                            </td>\r\n                                             <td class=\"text-center\">\r\n                                                <div class=\"custom-control custom-checkbox\">\r\n                                                    <input type=\"checkbox\" :value=\"inneritem.ID\"\r\n                                                        v-on:click=\"checkAllOuterMainCheckboxes($event,parentIndex)\"\r\n                                                        :id=\"'chkinner_4' + inneritem.ID\" data-change-id=\"no\"\r\n                                                        class=\"deletable custom-control-input\" name=\"push\"\r\n                                                        :checked=\"inneritem.IS_PUSH_NOTIFICATION == 1 ? 'checked' : ''\">\r\n                                                    <label class=\"custom-control-label\"\r\n                                                        :for=\"'chkinner_4' + inneritem.ID\"></label>\r\n                                                </div>\r\n                                            </td>\r\n                                        </tr>\r\n                                    </tbody>\r\n                                </table>\r\n                            </div>\r\n                            <div class=\"col-lg-12\">\r\n                                <div class=\"float-right mt-3\">\r\n                                   <a title=\"Save\" class=\"btn btn-success mr-2\" v-on:click=\"SubmitNotification\"><em class=\"fa fa-save pr-2\"></em>{{$t(\"Save\")}}</a>\r\n                                   <a title=\"Cancel\" class=\"btn btn-danger\" v-on:click=\"Cancel\"><em class=\"fa fa-close pr-2\"></em>{{$t(\"Cancel\")}}</a>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <AddCompanySetup :recordId=\"recordId\" :title=\"$t('NotificationType')\" v-if=\"showCompanyNotification\"\r\n            v-on:close=\"showCompanyNotification = false; recordId = 0\"\r\n            v-on:addReloadData=\"FetchData(); showCompanyNotification = false; recordId = 0\"\r\n            v-bind:moduleName=\"'CompanyNotification'\" v-bind:emitName=\"'addReloadData'\"\r\n            v-bind:addApiUrl=\"'/CompanyNotification/add'\" v-bind:subModule=\"'CompanyNotification'\" />\r\n    </div>\r\n</template>\r\n<script>\r\nimport CompanyNotificationDataService from \"@/services/DataService\";\r\nimport AddCompanySetup from \"@/components/Modals/AddCompanySetup.vue\";\r\nimport LeftColumn from \"../LeftColumn.vue\";\r\nimport DataService from \"../../../services/DataService\";\r\nexport default {\r\n    components: {\r\n        LeftColumn,\r\n        AddCompanySetup,\r\n    },\r\n    props: {\r\n        sourcetype:\r\n        {\r\n            type: String,\r\n            required: true\r\n        }\r\n    },\r\n    data() {\r\n        return {\r\n            recordId: 0,\r\n            showCompanyNotification: false,\r\n            noRecord: false,\r\n            isLoading: false,\r\n            GetNotificationData: [],\r\n            GetMainModuleData:[],\r\n            activeIndex: null  // track expanded row\r\n        }\r\n    },\r\n    async created() {\r\n        var vm = this;\r\n        await vm.FetchData();\r\n        setTimeout(function () {\r\n            vm.checkAllCheckboxes();\r\n        }, 1000);\r\n    },\r\n    methods: {\r\n        Cancel(){\r\n            var vm = this;\r\n            vm.isLoading= true;\r\n            vm.FetchData();\r\n            setTimeout(function () {\r\n                vm.checkAllCheckboxes();\r\n                vm.isLoading= false;\r\n        }, 1000);\r\n        },\r\n        toggleAccordion(index) {\r\n        this.activeIndex = this.activeIndex === index ? null : index;\r\n        },\r\n\r\n    \r\n  \r\n        async FetchData() {\r\n            \r\n            var vm = this;\r\n            var params = `moduleName=CompanyNotification&submoduleName=CompanyNotification`;\r\n            await CompanyNotificationDataService.GetNotificationTypeForCompany(params).then(response => {\r\n                //debugger;\r\n                if (response.data != null) {\r\n                    var getResponsedata = [];\r\n                    vm.GetNotificationData=[];\r\n                    vm.GetMainModuleData=[];\r\n                    var tempdata = null;\r\n                   \r\n                    getResponsedata = response.data.result;\r\n                    getResponsedata.forEach(item => {\r\n                        if (item.MODULE_ID == tempdata) {\r\n                            var checkifexist = vm.GetNotificationData.findIndex(x => x.ModuleId == tempdata);\r\n                            if (checkifexist > -1) {\r\n                                vm.GetNotificationData[checkifexist].GroupedSubmodule.push(item);\r\n                            }\r\n                        } else {\r\n                            var gettemparray = [];\r\n                            gettemparray.push(item);\r\n                            vm.GetNotificationData.push({\r\n                                ModuleName: item.MODULE_NAME, ModuleId: item.MODULE_ID, IS_EMAIL_NOTIFICATION: item.IS_EMAIL_NOTIFICATION,\r\n                                IS_INBOX_NOTIFICATION: item.IS_INBOX_NOTIFICATION, IS_MOBILE_NOTIFICATION: item.IS_MOBILE_NOTIFICATION,IS_PUSH_NOTIFICATION: item.IS_PUSH_NOTIFICATION\r\n                                , GroupedSubmodule: gettemparray\r\n                            })\r\n                            tempdata = item.MODULE_ID;\r\n                        }\r\n                        vm.GetMainModuleData.push({ id : item.ID,\r\n                            email : item.IS_EMAIL_NOTIFICATION,\r\n                            inbox : item.IS_INBOX_NOTIFICATION,\r\n                            mobile : item.IS_MOBILE_NOTIFICATION,\r\n                            push : item.IS_PUSH_NOTIFICATION});\r\n                    })\r\n                }\r\n            })\r\n        },\r\n        CheckMainCheckboxes(id, value) {\r\n            var vm = this;\r\n            var array = document.getElementsByTagName(\"input\");\r\n            for (var i = 0; i < array.length; i++) {\r\n                if (array[i].type == \"checkbox\") {\r\n                    if (array[i].id.includes(id)) {\r\n                        array[i].checked = value;\r\n                    }\r\n                }\r\n            }\r\n        },\r\n        checkAllinnerCheckboxes(value,array){\r\n            var vm = this;\r\n            vm.GetNotificationData.forEach(item=>{\r\n                if(item.ModuleId === parseInt(array.value)){\r\n                    item.GroupedSubmodule.forEach(inneritem=>{\r\n                        if(value == 'email'){\r\n                            inneritem.IS_EMAIL_NOTIFICATION = array.checked == true ? 1 : 0;\r\n                            item.IS_EMAIL_NOTIFICATION = array.checked == true ? 1 : 0;\r\n                        }else if(value == 'inbox'){\r\n                            inneritem.IS_INBOX_NOTIFICATION = array.checked == true ? 1 : 0;\r\n                            item.IS_INBOX_NOTIFICATION = array.checked == true ? 1 : 0;\r\n                        }else if(value == 'mobile'){\r\n                            inneritem.IS_MOBILE_NOTIFICATION = array.checked == true ? 1 : 0;\r\n                            item.IS_MOBILE_NOTIFICATION = array.checked == true ? 1 : 0;\r\n                        }\r\n                        else if(value == 'push'){\r\n                            inneritem.IS_PUSH_NOTIFICATION = array.checked == true ? 1 : 0;\r\n                            item.IS_PUSH_NOTIFICATION = array.checked == true ? 1 : 0;\r\n                        }\r\n                        var checkexist = vm.GetMainModuleData.find(x=>x.id === inneritem.ID);\r\n                        if(checkexist != undefined){\r\n                            checkexist.id = inneritem.ID;\r\n                            checkexist.email = inneritem.IS_EMAIL_NOTIFICATION;\r\n                            checkexist.inbox = inneritem.IS_INBOX_NOTIFICATION;\r\n                            checkexist.mobile = inneritem.IS_MOBILE_NOTIFICATION;\r\n                            checkexist.push = inneritem.IS_PUSH_NOTIFICATION;\r\n                        }else{\r\n                            vm.GetMainModuleData.push({id:inneritem.ID,email:inneritem.IS_EMAIL_NOTIFICATION,inbox:inneritem.IS_INBOX_NOTIFICATION,mobile:inneritem.IS_MOBILE_NOTIFICATION,push:inneritem.IS_PUSH_NOTIFICATION})\r\n                        }\r\n                    })\r\n                }\r\n            })\r\n        },\r\n        checkAllCheckboxes(event,chkvalue,value,index) {\r\n            var vm = this;\r\n            var inneritemvalue = true;\r\n            var mainoutervalue = true;\r\n            if(event != undefined){\r\n                vm.GetNotificationData.forEach((item,outerindex)=>{\r\n                    item.GroupedSubmodule.forEach((inneritem,innerindex)=>{\r\n                        if(event.target.value == inneritem.MODULE_ID && index == outerindex && value == 'email'){\r\n                            vm.checkAllinnerCheckboxes(value,event.target);\r\n                        }else if(event.target.value == inneritem.MODULE_ID && index == outerindex && value == 'inbox'){\r\n                            vm.checkAllinnerCheckboxes(value,event.target);\r\n                        }else if(event.target.value == inneritem.MODULE_ID && index == outerindex && value == 'mobile'){\r\n                            vm.checkAllinnerCheckboxes(value,event.target);\r\n                        }\r\n                        else if(event.target.value == inneritem.MODULE_ID && index == outerindex && value == 'push'){\r\n                            vm.checkAllinnerCheckboxes(value,event.target);\r\n                        }\r\n                    })\r\n                    if(item.IS_EMAIL_NOTIFICATION == 0 && value == 'email'){\r\n                        mainoutervalue = false;\r\n                    }else if(item.IS_INBOX_NOTIFICATION == 0 && value == 'inbox'){\r\n                        mainoutervalue = false;\r\n                    }else if(item.IS_MOBILE_NOTIFICATION == 0 && value == 'mobile'){\r\n                        mainoutervalue = false;\r\n                    }\r\n                    else if(item.IS_PUSH_NOTIFICATION == 0 && value == 'push'){\r\n                        mainoutervalue = false;\r\n                    }\r\n                })\r\n                if(value == 'email'){\r\n                    mainoutervalue == false ? vm.CheckMainCheckboxes('chkupper_1', '') : vm.CheckMainCheckboxes('chkupper_1', 'checked');\r\n                }else if (value == 'inbox'){\r\n                    mainoutervalue == false? vm.CheckMainCheckboxes('chkupper_2', '') : vm.CheckMainCheckboxes('chkupper_2', 'checked');\r\n                }else if (value == 'mobile'){\r\n                    mainoutervalue == false ? vm.CheckMainCheckboxes('chkupper_3', '') : vm.CheckMainCheckboxes('chkupper_3', 'checked');\r\n                }\r\n                else if (value == 'push'){\r\n                    mainoutervalue == false ? vm.CheckMainCheckboxes('chkupper_4', '') : vm.CheckMainCheckboxes('chkupper_4', 'checked');\r\n                }\r\n            }else{\r\n                var array = document.getElementsByClassName(\"deletable custom-control-input\");\r\n                for (var i = 0; i < array.length; i++) {\r\n                    if (array[i].type == \"checkbox\") {\r\n                        if ((array[i].id.includes('chk_1') || array[i].id.includes('chkinner_1')) && chkvalue != undefined ? chkvalue == array[i].id : array[i].id.includes('chk_1') || array[i].id.includes('chkinner_1')) {\r\n                            if (array[i].checked == true) {\r\n                                vm.CheckMainCheckboxes('chkupper_1', 'checked');\r\n                            } else {\r\n                                vm.CheckMainCheckboxes('chkupper_1', '');\r\n                                break;\r\n                            }\r\n                        } else if ((array[i].id.includes('chk_2') || array[i].id.includes('chkinner_2')) && chkvalue != undefined ? chkvalue == array[i].id : array[i].id.includes('chk_2') || array[i].id.includes('chkinner_2')) {\r\n                            if (array[i].checked == true) {\r\n                                vm.CheckMainCheckboxes('chkupper_2', 'checked');\r\n                            } else {\r\n                                vm.CheckMainCheckboxes('chkupper_2', '');\r\n                                break;\r\n                            }\r\n                        } else if ((array[i].id.includes('chk_3') || array[i].id.includes('chkinner_3')) && chkvalue != undefined ? chkvalue == array[i].id : array[i].id.includes('chk_3') || array[i].id.includes('chkinner_3')) {\r\n                            if (array[i].checked == true) {\r\n                                vm.CheckMainCheckboxes('chkupper_3', 'checked');\r\n                            } else {\r\n                                vm.CheckMainCheckboxes('chkupper_3', '');\r\n                                break;\r\n                            }\r\n                        }\r\n                        else if ((array[i].id.includes('chk_4') || array[i].id.includes('chkinner_4')) && chkvalue != undefined ? chkvalue == array[i].id : array[i].id.includes('chk_4') || array[i].id.includes('chkinner_4')) {\r\n                            if (array[i].checked == true) {\r\n                                vm.CheckMainCheckboxes('chkupper_4', 'checked');\r\n                            } else {\r\n                                vm.CheckMainCheckboxes('chkupper_4', '');\r\n                                break;\r\n                            }\r\n                        }\r\n                    }\r\n                }\r\n            }\r\n        },\r\n        async SubmitNotification(){\r\n            var vm = this;\r\n            var obj={\r\n                MainData:vm.GetMainModuleData\r\n            };\r\n            //debugger;\r\n            await DataService.UpdateCompanyNotification(obj).then(response=>{      \r\n                 if (response.data.Result != null && response.data.Result.MAIN_ID > 0) {\r\n                    this.ShowAlert(this.$t('UpdatedSuccess',true,[this.$t('Notifications')]), 'success', true, this.$t('Alert'));\r\n                        this.$emit(this.emitName)\r\n                    } else {\r\n                        if(this.$t(response.data.Status) == 'Failure'){\r\n                            this.ShowAlert(this.$t('ErrorWhileSavingRecords'), \"danger\", false, this.$t(\"Alert\"));\r\n                        }\r\n                     }\r\n            }).catch(err=>{\r\n                console.log(err);\r\n            })\r\n        },\r\n        checkAllRowCheckboxes(event,value,type) {\r\n            var vm = this;\r\n            var array = document.getElementsByClassName(\"deletable custom-control-input\");\r\n            for (var i = 0; i < array.length; i++) {\r\n                if (array[i].type == \"checkbox\" && array[i].id.includes(value)) {\r\n                    vm.GetNotificationData.forEach(item=>{\r\n                        item.GroupedSubmodule.forEach(inneritem=>{\r\n                            if(type == 'email'){\r\n                                inneritem.IS_EMAIL_NOTIFICATION = event.target.checked == true ? 1 : 0;\r\n                                item.IS_EMAIL_NOTIFICATION = event.target.checked == true ? 1 : 0;\r\n                            }\r\n                            else if (type == 'inbox'){\r\n                                inneritem.IS_INBOX_NOTIFICATION = event.target.checked == true ? 1 : 0;\r\n                                item.IS_INBOX_NOTIFICATION = event.target.checked == true ? 1 : 0;\r\n                            }\r\n                            else if (type == 'mobile'){\r\n                                inneritem.IS_MOBILE_NOTIFICATION = event.target.checked == true ? 1 : 0;\r\n                                item.IS_MOBILE_NOTIFICATION = event.target.checked == true ? 1 : 0;\r\n                            }\r\n                            else if (type == 'push'){\r\n                                inneritem.IS_PUSH_NOTIFICATION = event.target.checked == true ? 1 : 0;\r\n                                item.IS_PUSH_NOTIFICATION = event.target.checked == true ? 1 : 0;\r\n                            }\r\n                            var checkexist = vm.GetMainModule