_NOTIFICATION = event.target.checked == true ? 1 : 0;\r\n                    }\r\n                    if(index == outerindex && inneritem.ID == event.target.value){\r\n                        var checkexist = vm.GetMainModuleData.find(x=>x.id === inneritem.ID);\r\n                        if(checkexist != undefined){\r\n                            checkexist.id = inneritem.ID;\r\n                            checkexist.email = inneritem.IS_EMAIL_NOTIFICATION;\r\n                            checkexist.inbox = inneritem.IS_INBOX_NOTIFICATION;\r\n                            checkexist.mobile = inneritem.IS_MOBILE_NOTIFICATION;\r\n                            checkexist.push = inneritem.IS_PUSH_NOTIFICATION;\r\n                        }else{\r\n                            vm.GetMainModuleData.push({id:inneritem.ID,email:inneritem.IS_EMAIL_NOTIFICATION,inbox:inneritem.IS_INBOX_NOTIFICATION,mobile:inneritem.IS_MOBILE_NOTIFICATION,push:inneritem.IS_PUSH_NOTIFICATION})\r\n                        }\r\n                    }\r\n\r\n                    if(inneritem.IS_EMAIL_NOTIFICATION == 0 && index == outerindex && event.target.name == 'email'){\r\n                        item.IS_EMAIL_NOTIFICATION = 0;\r\n                        isCheckedAll = false;\r\n                    }else if(inneritem.IS_INBOX_NOTIFICATION == 0 && index == outerindex && event.target.name == 'inbox'){\r\n                        item.IS_INBOX_NOTIFICATION = 0;\r\n                        isCheckedAll = false;\r\n                    }else if(inneritem.IS_MOBILE_NOTIFICATION == 0 && index == outerindex && event.target.name == 'mobile'){\r\n                        item.IS_MOBILE_NOTIFICATION = 0;\r\n                        isCheckedAll = false;\r\n                    }\r\n                    else if(inneritem.IS_PUSH_NOTIFICATION == 0 && index == outerindex && event.target.name == 'push'){\r\n                        item.IS_PUSH_NOTIFICATION = 0;\r\n                        isCheckedAll = false;\r\n            